    public getLoggerInternal(props: {
        console?: Console,
        storage?: StorageSettings<string>,
        friendlyName?: string,
    }): Console {
        const { console, storage, friendlyName } = props;
        if (console) {
            return getBaseLogger({
                console,
                storage,
                friendlyName
            });
        } else {
            if (!this.mainLogger) {
                this.mainLogger = getBaseLogger({
                    console: this.console,
                    storage: this.storageSettings,
                    friendlyName: this.opts.pluginFriendlyName
                });
            }

            return this.mainLogger
        }
    }
